   565	pub(crate) fn drain_pending_repo_storage_deletions_report(
   566	    state: &AppState,
   567	) -> Result<RepoStorageCleanupDrainReport, ApiError> {
   568	    let metadata = state.metadata.clone();
   569	    let state = state.clone();
   570	    metadata.update_pending_repo_storage_deletions(move |pending, live_repo_ids| {
   571	        let mut report = RepoStorageCleanupDrainReport::default();
   572	        let mut retained = Vec::new();
   573	        for cleanup in pending {
   574	            if live_repo_ids.contains(&repo_id(&cleanup.owner_handle, &cleanup.repo_name)) {
   575	                retained.push(cleanup);
   576	                continue;
   577	            }
   578	
   579	            report.attempted += 1;
   580	            match crate::git::storage::delete_repo_storage(
   581	                &state,
   582	                &cleanup.owner_handle,
   583	                &cleanup.repo_name,
   584	            ) {
   585	                Ok(()) => {
   586	                    report.deleted += 1;
   587	                }
   588	                Err(error) => {
   589	                    tracing::warn!(
   590	                        ?error,
   591	                        owner = %cleanup.owner_handle,
   592	                        repo = %cleanup.repo_name,
   593	                        "failed to clean deleted repo filesystem storage"
   594	                    );
   595	                    report.failed.push(RepoStorageCleanupFailure {
   596	                        owner_handle: cleanup.owner_handle.clone(),
   597	                        repo_name: cleanup.repo_name.clone(),
   598	                        error: error.message,
   599	                    });
   600	                    retained.push(cleanup);
   601	                }
   602	            }
   603	        }
   604	        report.retained = retained.len();
   605	        Ok((report, retained))
   606	    })
   607	}
