   637	pub(crate) fn best_effort_cleanup_rollback_source_blobs(state: &AppState, blobs: &[SourceBlob]) {
   638	    if blobs.is_empty() {
   639	        return;
   640	    }
   641	    match persist_pending_source_blob_deletions(state, blobs) {
   642	        Ok(()) => best_effort_drain_pending_source_blob_deletions(state),
   643	        Err(queue_error) => {
   644	            tracing::warn!(?queue_error, "failed to queue rollback source blob cleanup");
   645	            if let Err(delete_error) = delete_unreferenced_source_blobs(state, blobs) {
   646	                tracing::warn!(
