   655	pub(crate) fn drain_pending_source_blob_deletions_report(
   656	    state: &AppState,
   657	) -> Result<SourceBlobCleanupDrainReport, ApiError> {
   658	    let metadata = state.metadata.clone();
   659	    let state = state.clone();
   660	    metadata.update_pending_source_blob_deletions(move |pending, referenced_blob_keys| {
   661	        let mut report = SourceBlobCleanupDrainReport::default();
   662	        if pending.is_empty() {
   663	            return Ok((report, pending));
   664	        }
   665	
   666	        let unreferenced = unreferenced_source_blobs_by_key(referenced_blob_keys, &pending);
   667	        report.skipped_referenced = pending.len().saturating_sub(unreferenced.len());
   668	        report.attempted = unreferenced.len();
   669	        let delete_report = delete_source_blob_storage(&state, &unreferenced);
   670	        report.deleted = delete_report.deleted_keys.len();
   671	        report.failed_object_deletes = delete_report.failed;
   672	        let retained = unreferenced
   673	            .into_iter()
   674	            .filter(|blob| !delete_report.deleted_keys.contains(&blob.object_key))
   675	            .collect::<Vec<_>>();
   676	        report.retained = retained.len();
   677	        Ok((report, retained))
   678	    })
   679	}
