   681	pub(crate) fn drain_pending_source_blob_deletions(state: &AppState) -> Result<(), ApiError> {
   682	    let report = drain_pending_source_blob_deletions_report(state)?;
   683	    match report.failed_object_deletes.first().map(|failure| {
   684	        ApiError::service_unavailable(format!(
   685	            "failed to clean source blob storage {}: {}",
   686	            failure.object_key, failure.error
   687	        ))
   688	    }) {
   689	        Some(error) => Err(error),
   690	        None => Ok(()),
   691	    }
   692	}
