   489	pub(crate) fn git_process_output_with_timeout(
   490	    command: &mut Command,
   491	    stdin: Option<Vec<u8>>,
   492	    timeout: Duration,
   493	) -> Result<Output, ApiError> {
   494	    if stdin.is_some() {
   495	        command.stdin(Stdio::piped());
   496	    }
   497	    configure_process_group(command);
   498	    let mut child = command
   499	        .stdout(Stdio::piped())
   500	        .stderr(Stdio::piped())
   501	        .spawn()
   502	        .map_err(|error| ApiError::service_unavailable(format!("failed to run Git: {error}")))?;
   503	    let stdin_writer = if let Some(input) = stdin {
   504	        let mut child_stdin = child
   505	            .stdin
   506	            .take()
   507	            .ok_or_else(|| ApiError::internal_message("failed to open Git stdin"))?;
   508	        Some(thread::spawn(move || {
   509	            child_stdin.write_all(&input)?;
   510	            child_stdin.flush()
   511	        }))
   512	    } else {
   513	        None
   514	    };
   515	    wait_with_timeout(child, stdin_writer, timeout, "Git command")
   516	}
