   518	fn wait_with_timeout(
   519	    mut child: std::process::Child,
   520	    stdin_writer: Option<thread::JoinHandle<std::io::Result<()>>>,
   521	    timeout: Duration,
   522	    action: &str,
   523	) -> Result<Output, ApiError> {
   524	    let mut stdout = child
   525	        .stdout
   526	        .take()
   527	        .ok_or_else(|| ApiError::internal_message("failed to open Git stdout"))?;
   528	    let stderr = child
   529	        .stderr
   530	        .take()
   531	        .ok_or_else(|| ApiError::internal_message("failed to open Git stderr"))?;
   532	    let stdout_reader = thread::spawn(move || {
   533	        let mut bytes = Vec::new();
   534	        stdout.read_to_end(&mut bytes).map(|_| bytes)
   535	    });
   536	    let stderr_reader = thread::spawn(move || read_stderr_diagnostic(stderr));
   537	
   538	    let started_at = Instant::now();
   539	    let mut status = None;
   540	    let status = loop {
   541	        if status.is_none() {
   542	            status = child.try_wait().map_err(ApiError::internal)?;
   543	        }
   544	        let stdin_done = stdin_writer
   545	            .as_ref()
   546	            .is_none_or(thread::JoinHandle::is_finished);
   547	        if stdout_reader.is_finished()
   548	            && stderr_reader.is_finished()
   549	            && stdin_done
   550	            && let Some(status) = status.take()
   551	        {
   552	            break status;
   553	        }
   554	        if started_at.elapsed() >= timeout {
   555	            kill_process_group(&mut child);
   556	            if status.is_none() {
   557	                let _status = child.wait().map_err(ApiError::internal)?;
   558	            }
   559	            drop(stdin_writer);
   560	            let _stdout = join_reader(stdout_reader)?;
   561	            let stderr = join_reader(stderr_reader)?;
   562	            let message = truncated_git_stderr(&stderr);
   563	            return Err(ApiError::service_unavailable(format!(
   564	                "{action} timed out after {}ms{}{}",
   565	                timeout.as_millis(),
   566	                if message.is_empty() { "" } else { ": " },
   567	                message
   568	            )));
   569	        }
   570	        let remaining = timeout.saturating_sub(started_at.elapsed());
   571	        thread::sleep(remaining.min(Duration::from_millis(1)));
   572	    };
   573	
   574	    if let Some(stdin_writer) = stdin_writer {
   575	        join_writer(stdin_writer)?;
   576	    }
   577	    let stdout = join_reader(stdout_reader)?;
   578	    let stderr = join_reader(stderr_reader)?;
   579	    Ok(Output {
   580	        status,
   581	        stdout,
   582	        stderr,
   583	    })
   584	}
