   586	fn join_reader(handle: thread::JoinHandle<std::io::Result<Vec<u8>>>) -> Result<Vec<u8>, ApiError> {
   587	    handle
   588	        .join()
   589	        .map_err(|_| ApiError::internal_message("Git output reader panicked"))?
   590	        .map_err(ApiError::internal)
   591	}
   592	
   593	fn join_writer(handle: thread::JoinHandle<std::io::Result<()>>) -> Result<(), ApiError> {
   594	    match handle
   595	        .join()
   596	        .map_err(|_| ApiError::internal_message("Git stdin writer panicked"))?
   597	    {
   598	        Ok(()) => Ok(()),
   599	        Err(error) if error.kind() == ErrorKind::BrokenPipe => Ok(()),
   600	        Err(error) => Err(ApiError::internal(error)),
   601	    }
   602	}
