   604	fn read_stderr_diagnostic(mut stderr: impl Read) -> std::io::Result<Vec<u8>> {
   605	    let max_retained = GIT_STDERR_DIAGNOSTIC_BYTES.saturating_add(1);
   606	    let mut retained = Vec::new();
   607	    let mut buffer = [0_u8; 8 * 1024];
   608	    loop {
   609	        let read = stderr.read(&mut buffer)?;
   610	        if read == 0 {
   611	            return Ok(retained);
   612	        }
   613	        let remaining = max_retained.saturating_sub(retained.len());
   614	        if remaining > 0 {
   615	            retained.extend_from_slice(&buffer[..read.min(remaining)]);
